import type { Metadata } from 'next';

export const metadata: Metadata = {
    title: 'Contact | John Doe Portfolio',
    description: 'Get in touch with John Doe for freelance projects or employment opportunities.',
};

export default function Contact() {
    return (
        <div className="container animate-fade-in">
            <div style={styles.header}>
                <h1 style={styles.title}>Get in <span className="gradient-text">Touch</span></h1>
                <p style={styles.subtitle}>I'm currently available for freelance work and full-time positions.</p>
            </div>

            <div style={styles.content}>
                <div className="glass-panel" style={styles.formContainer}>
                    <form style={styles.form}>
                        <div style={styles.formGroup}>
                            <label htmlFor="name" style={styles.label}>Name</label>
                            <input type="text" id="name" className="form-input" placeholder="Your Name" required />
                        </div>

                        <div style={styles.formGroup}>
                            <label htmlFor="email" style={styles.label}>Email</label>
                            <input type="email" id="email" className="form-input" placeholder="you@example.com" required />
                        </div>

                        <div style={styles.formGroup}>
                            <label htmlFor="message" style={styles.label}>Message</label>
                            <textarea id="message" className="form-input" rows={6} placeholder="How can I help you?" required style={styles.textarea}></textarea>
                        </div>

                        <button type="submit" className="btn-primary" style={styles.submitBtn}>
                            Send Message
                        </button>
                    </form>
                </div>

                <div style={styles.info}>
                    <div className="glass-panel">
                        <h3 style={{ fontSize: '1.5rem', marginBottom: '1rem' }}>Contact Information</h3>
                        <p style={{ color: 'var(--text-secondary)', marginBottom: '1.5rem' }}>
                            Feel free to reach out via email or connect with me on social media.
                            I try to respond to all inquiries within 24 hours.
                        </p>
                        <ul style={styles.infoList}>
                            <li><strong>Email:</strong> hello@johndoe.com</li>
                            <li><strong>Phone:</strong> +1 (555) 123-4567</li>
                            <li><strong>Location:</strong> San Francisco, CA</li>
                        </ul>

                        <h3 style={{ fontSize: '1.5rem', margin: '2rem 0 1rem 0' }}>Social Profiles</h3>
                        <div style={styles.socialGrid}>
                            <a href="https://github.com" target="_blank" rel="noreferrer" className="btn-secondary" style={styles.socialLink}>GitHub</a>
                            <a href="https://linkedin.com" target="_blank" rel="noreferrer" className="btn-secondary" style={styles.socialLink}>LinkedIn</a>
                            <a href="https://twitter.com" target="_blank" rel="noreferrer" className="btn-secondary" style={styles.socialLink}>Twitter</a>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

const styles = {
    header: {
        padding: '4rem 0 3rem 0',
        textAlign: 'center' as const,
    },
    title: {
        fontSize: '3.5rem',
    },
    subtitle: {
        fontSize: '1.2rem',
        color: 'var(--text-secondary)',
        marginTop: '1rem',
    },
    content: {
        display: 'grid',
        gridTemplateColumns: 'minmax(0, 2fr) minmax(0, 1fr)',
        gap: '3rem',
        paddingBottom: '4rem',
    },
    formContainer: {
        padding: '3rem',
    },
    form: {
        display: 'flex',
        flexDirection: 'column' as const,
    },
    formGroup: {
        display: 'flex',
        flexDirection: 'column' as const,
        marginBottom: '1rem',
    },
    label: {
        marginBottom: '0.5rem',
        fontWeight: 500,
        color: 'var(--text-primary)',
    },
    textarea: {
        resize: 'vertical' as const,
        fontFamily: 'inherit',
    },
    submitBtn: {
        marginTop: '1rem',
        alignSelf: 'flex-start',
    },
    info: {
        display: 'flex',
        flexDirection: 'column' as const,
    },
    infoList: {
        listStyle: 'none',
        padding: 0,
        display: 'flex',
        flexDirection: 'column' as const,
        gap: '1rem',
        color: 'var(--text-secondary)',
    },
    socialGrid: {
        display: 'flex',
        flexDirection: 'column' as const,
        gap: '1rem',
    },
    socialLink: {
        textAlign: 'center' as const,
        display: 'block',
        width: '100%',
    }
};

import Link from 'next/link';

export default function Home() {
  return (
    <div className="container">
      <section style={styles.heroSection}>
        <div style={styles.heroContent} className="animate-fade-in">
          <h1 style={styles.title}>
            Hi, I'm <span className="gradient-text">John Doe</span>
          </h1>
          <h2 style={styles.subtitle}>
            Fullstack Developer & UI/UX Enthusiast
          </h2>
          <p style={styles.description}>
            I build exceptional and accessible digital experiences for the modern web. Let's create something amazing together.
          </p>
          <div style={styles.buttonGroup}>
            <Link href="/projects" className="btn-primary">
              View My Work
            </Link>
            <Link href="/contact" className="btn-secondary">
              Contact Me
            </Link>
          </div>
        </div>
      </section>

      {/* Featured Section */}
      <section style={styles.featureSection} className="animate-fade-in delay-200">
        <h3 style={styles.sectionTitle}>What I Do</h3>
        <div style={styles.grid}>
          <div className="glass-panel">
            <h4 style={styles.cardTitle}>Frontend Development</h4>
            <p style={{ color: 'var(--text-secondary)' }}>Building responsive, interactive UIs with React, Next.js, and modern CSS.</p>
          </div>
          <div className="glass-panel">
            <h4 style={styles.cardTitle}>Backend Development</h4>
            <p style={{ color: 'var(--text-secondary)' }}>Creating scalable APIs and database architectures using Node.js and PostgreSQL.</p>
          </div>
          <div className="glass-panel">
            <h4 style={styles.cardTitle}>UI/UX Design</h4>
            <p style={{ color: 'var(--text-secondary)' }}>Designing intuitive and beautiful user experiences visually focused on conversion.</p>
          </div>
        </div>
      </section>
    </div>
  );
}

const styles = {
  heroSection: {
    minHeight: '80vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    textAlign: 'center' as const,
  },
  heroContent: {
    maxWidth: '800px',
  },
  title: {
    fontSize: '4rem',
    marginBottom: '1rem',
    letterSpacing: '-0.02em',
  },
  subtitle: {
    fontSize: '2rem',
    color: 'var(--text-secondary)',
    marginBottom: '1.5rem',
    fontWeight: 500,
  },
  description: {
    fontSize: '1.2rem',
    color: 'var(--text-secondary)',
    marginBottom: '3rem',
    maxWidth: '600px',
    margin: '0 auto 3rem auto',
    lineHeight: 1.6,
  },
  buttonGroup: {
    display: 'flex',
    gap: '1rem',
    justifyContent: 'center',
  },
  featureSection: {
    padding: '4rem 0',
  },
  sectionTitle: {
    fontSize: '2.5rem',
    textAlign: 'center' as const,
    marginBottom: '3rem',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
    gap: '2rem',
  },
  cardTitle: {
    fontSize: '1.5rem',
    marginBottom: '1rem',
    color: 'var(--text-primary)',
  },
};

import type { Metadata } from 'next';

export const metadata: Metadata = {
    title: 'Projects | John Doe Portfolio',
    description: 'View the latest software development projects built by John Doe.',
};

const projects = [
    {
        id: 1,
        title: 'E-Commerce Platform',
        description: 'A full-scale e-commerce solution with Next.js, Stripe integration, and real-time inventory.',
        stack: ['Next.js', 'TypeScript', 'Tailwind', 'Stripe'],
        link: '#',
    },
    {
        id: 2,
        title: 'AI Dashboard',
        description: 'Analytics dashboard featuring AI-driven insights with interactive data visualizations.',
        stack: ['React', 'Recharts', 'Node.js', 'OpenAI'],
        link: '#',
    },
    {
        id: 3,
        title: 'Task Manager SAAS',
        description: 'A collaborative task management tool with real-time updates and team spaces.',
        stack: ['Vue.js', 'Firebase', 'Express', 'PostgreSQL'],
        link: '#',
    },
    {
        id: 4,
        title: 'Social Media App',
        description: 'Mobile-first social platform for sharing photos and stories with real-time chat.',
        stack: ['React Native', 'GraphQL', 'AWS'],
        link: '#',
    },
];

export default function Projects() {
    return (
        <div className="container animate-fade-in">
            <div style={styles.header}>
                <h1 style={styles.title}>My <span className="gradient-text">Projects</span></h1>
                <p style={styles.subtitle}>A collection of things I've built recently.</p>
            </div>

            <div style={styles.grid}>
                {projects.map((project, index) => (
                    <div key={project.id} className="glass-panel" style={{ ...styles.card, animationDelay: `${index * 0.1}s` }}>
                        <h2 style={styles.cardTitle}>{project.title}</h2>
                        <p style={styles.cardDescription}>{project.description}</p>

                        <div style={styles.tagContainer}>
                            {project.stack.map(tech => (
                                <span key={tech} style={styles.tag}>{tech}</span>
                            ))}
                        </div>

                        <div style={styles.cardActions}>
                            <a href={project.link} className="btn-secondary" style={styles.actionButton}>
                                View Project
                            </a>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

const styles = {
    header: {
        padding: '4rem 0 3rem 0',
        textAlign: 'center' as const,
    },
    title: {
        fontSize: '3.5rem',
        marginBottom: '1rem',
    },
    subtitle: {
        fontSize: '1.2rem',
        color: 'var(--text-secondary)',
    },
    grid: {
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
        gap: '2.5rem',
        paddingBottom: '4rem',
    },
    card: {
        display: 'flex',
        flexDirection: 'column' as const,
        height: '100%',
    },
    cardTitle: {
        fontSize: '1.5rem',
        marginBottom: '1rem',
    },
    cardDescription: {
        color: 'var(--text-secondary)',
        marginBottom: '1.5rem',
        flex: 1,
    },
    tagContainer: {
        display: 'flex',
        flexWrap: 'wrap' as const,
        gap: '0.5rem',
        marginBottom: '2rem',
    },
    tag: {
        fontSize: '0.8rem',
        padding: '0.2rem 0.8rem',
        background: 'rgba(109, 40, 217, 0.2)',
        color: '#c084fc',
        borderRadius: '999px',
        border: '1px solid rgba(109, 40, 217, 0.4)',
    },
    cardActions: {
        marginTop: 'auto',
    },
    actionButton: {
        padding: '0.6rem 1.5rem',
        fontSize: '0.9rem',
    }
};
